import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What BMI is considered underweight?", a: "A BMI below 18.5 is generally classified as underweight for adults." },
  { q: "What are the health risks of being underweight?", a: "Being underweight may be linked with nutrient deficiencies, low energy, immune issues, fertility problems, bone loss, and heart or hormone concerns." },
  { q: "How do you gain weight in a healthy way?", a: "A healthcare professional can help with a plan that may include regular meals, calorie-dense nutritious foods, strength training, and support for any underlying condition." },
  { q: "What is a dangerously low BMI?", a: "Very low BMI levels, especially below 16, can be medically serious. Anyone with rapid weight loss, fainting, chest pain, or eating disorder symptoms should seek medical help." },
  { q: "Where can you get help for eating disorders?", a: "Professional support is important. NEDA offers screening and support resources, and anyone in immediate danger should contact local emergency services." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function bmi(weight: number, height: number) {
  return weight / (height * height) * 703;
}
function classForBmi(value: number) {
  if (value < 15) return "Very severely underweight";
  if (value < 16) return "Severely underweight";
  if (value < 17) return "Moderately underweight";
  if (value < 18.5) return "Underweight";
  if (value < 25) return "Normal weight";
  if (value < 30) return "Overweight";
  return "Obese";
}
function healthyRange(height: number) {
  return { low: 18.5 * height * height / 703, high: 24.9 * height * height / 703 };
}

export default function AnorexicBMICalculator() {
  const [height, setHeight] = useState(66);
  const [weight, setWeight] = useState(115);
  const result = useMemo(() => { const value = bmi(weight, height); return { value, label: classForBmi(value), range: healthyRange(height) }; }, [height, weight]);
  const rows = [["Under 15", "Very severely underweight", "Very high", "Seek professional medical support"], ["15-15.9", "Severely underweight", "High", "Medical evaluation recommended"], ["16-16.9", "Moderately underweight", "Elevated", "Talk with a healthcare professional"], ["17-18.4", "Underweight", "Possible risk", "Review nutrition and health context"], ["18.5-24.9", "Normal", "Lower average risk", "Maintain healthy habits"], ["25-29.9", "Overweight", "Possible risk", "Discuss overall health markers"], ["30 plus", "Obese", "Increased risk", "Consider professional guidance"]];
  return (
    <>
      <SEOHead title="Free Underweight BMI Calculator Online - Calculate BMI and Healthy Weight Range | CalcHive" description="Free online underweight BMI calculator. Calculate your BMI, understand underweight health risks and find your healthy weight range instantly. 100% free, no signup required." canonical="/anorexic-bmi-calculator" keywords="free underweight BMI calculator, low BMI calculator free online, underweight calculator free, calculate underweight BMI free, healthy weight BMI calculator free" category="Health Calculators" breadcrumbName="Free Underweight BMI Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
<main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Underweight BMI Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate BMI, see underweight categories, and compare your result with a healthy weight range.</p></div><AdPlaceholder size="banner" className="mb-8" /><div className="mb-6 rounded-2xl border border-rose-200 bg-rose-50 p-4 text-sm text-rose-900 dark:border-rose-800 dark:bg-rose-950/30 dark:text-rose-100">BMI is just one health metric and cannot diagnose an eating disorder or overall health. If you are struggling with food, weight, or body image, please seek professional support. You can start with <a className="font-semibold underline" href="https://www.nationaleatingdisorders.org/help-support/contact-helpline" target="_blank" rel="noopener noreferrer">NEDA screening and support resources</a>.</div>
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Height (in)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (lb)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Your BMI</p><p className="text-5xl sm:text-6xl font-black text-white">{result.value.toFixed(1)}</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Classification</p><p className="text-lg font-extrabold">{result.label}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Healthy weight range</p><p className="text-lg font-extrabold">{result.range.low.toFixed(0)}-{result.range.high.toFixed(0)} lb</p></div></div></section><MedicalDisclaimer variant="eating-disorder" /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate BMI and Understand Underweight Categories for Free</h2><p className="text-muted-foreground leading-relaxed">BMI uses weight and height to estimate a broad weight category. It is a screening tool and should be interpreted with medical context.</p><h2 className="text-2xl font-bold">Health Risks of Being Underweight</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">BMI Classification and Health Implications</caption><thead className="bg-muted/60"><tr>{["BMI Range", "Classification", "Health Risk Level", "Recommended Action"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}>{r.map((c) => <td key={c} className="py-2.5 px-3">{c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free BMI Health Range Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this page as a gentle starting point for understanding BMI, not as a substitute for care from a clinician, dietitian, or mental health professional.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/anorexic-bmi-calculator" headingLevel="h3" /></main>
    </>
  );
}


